-- =============================================================================
-- 20260422124500_stat_tier_a_supabase_staging_safe_mode.sql
-- MR-1393 | STAT Mode B STAGING build | SAFE MODE
-- Project target: fglyvdykwgbuivikqoah
-- Input: _STAT_OUTPUTS/mcqs_final_1388_tier_a.json
-- IMPORTANT: This migration must NOT activate v5_tier_a as current dataset.
-- =============================================================================

begin;
-- STEP 1: Backups (staging safety snapshot)
create table if not exists public.dataset_questions_backup_pre_v5_tier_a_20260422 as table public.dataset_questions;
create table if not exists public.dataset_registry_backup_pre_v5_tier_a_20260422 as table public.dataset_registry;
-- Compatibility columns for staging metadata/filtering
alter table public.dataset_questions add column if not exists quality_tier text;
alter table public.dataset_registry add column if not exists description text;
alter table public.dataset_registry add column if not exists is_active boolean not null default false;
-- STEP 2 + 3: Tier A ingest into v5_tier_a
on conflict (dataset_version, question_id) do update set
  prompt       = excluded.prompt,
  choice_a     = excluded.choice_a,
  choice_b     = excluded.choice_b,
  choice_c     = excluded.choice_c,
  choice_d     = excluded.choice_d,
  answer       = excluded.answer,
  explanation  = excluded.explanation,
  quality_tier = excluded.quality_tier;
-- STEP 2 (continued): registry row insert without activation side effects
do $$
declare
  v_active_before text;
  v_active_after  text;
  v_anchor_ts     timestamptz;
  v_q_count       integer;
  v_hash          text;
begin
  select public.dataset_registry_current() into v_active_before;
  select coalesce(min(registered_at) - interval '1 second', now() - interval '10 years') into v_anchor_ts from public.dataset_registry;
  select count(*) into v_q_count from public.dataset_questions where dataset_version = 'v5_tier_a' and quality_tier = 'A';
  select public.dataset_canonical_hash('v5_tier_a') into v_hash;

  values ('v5_tier_a', v_hash, v_q_count, v_anchor_ts, '_STAT_OUTPUTS/mcqs_final_1388_tier_a.json', 'Tier A validated STAT questions (STAGING)', 'Tier A validated STAT questions (STAGING)', false)
  on conflict (dataset_version) do update set
    content_root_hash = excluded.content_root_hash,
    question_count    = excluded.question_count,
    registered_at     = excluded.registered_at,
    source_path       = excluded.source_path,
    notes             = excluded.notes,
    description       = excluded.description,
    is_active         = false;

  select public.dataset_registry_current() into v_active_after;
  if v_active_before is not null and v_active_after is distinct from v_active_before then
    raise exception 'activation_guard_failed: dataset_registry_current changed from % to %', v_active_before, v_active_after;
  end if;
end
$$;
-- STEP 5: SAFE RPC PREP (new function only; does not modify existing get_duel_pack)
create or replace function public.get_duel_pack_v5(
  p_duel_id uuid
)
returns jsonb
language plpgsql
security definer
set search_path = public, pg_temp
as $$
declare
  v_actor uuid := auth.uid();
  v_duel  public.duel_challenges%rowtype;
  v_prompts jsonb;
begin
  if v_actor is null then
    raise exception 'auth_required';
  end if;

  select * into v_duel
  from public.duel_challenges
  where id = p_duel_id
    and (challenger_id = v_actor or opponent_id = v_actor);

  if not found then
    raise exception 'duel_not_found';
  end if;

  if v_duel.content_hash is null or v_duel.sealed_at is null then
    raise exception 'duel_pack_unsealed';
  end if;

  select coalesce(
    jsonb_agg(
      jsonb_build_object(
        'question_id',   dq.question_id,
        'prompt',        dq.prompt,
        'choice_a',      dq.choice_a,
        'choice_b',      dq.choice_b,
        'choice_c',      dq.choice_c,
        'choice_d',      dq.choice_d,
        'display_order', v_duel.choices_order -> ((ord - 1)::int)
      )
      order by ord
    ),
    '[]'::jsonb
  )
  into v_prompts
  from unnest(v_duel.question_ids) with ordinality as u(qid, ord)
  join public.dataset_questions dq
    on dq.dataset_version = 'v5_tier_a'
   and dq.quality_tier    = 'A'
   and dq.question_id     = u.qid;

  return jsonb_build_object(
    'status',    'ok',
    'duel',      public.private_duel_envelope(v_duel),
    'questions', v_prompts
  );
end;
$$;
comment on function public.get_duel_pack_v5(uuid) is 'Staging-only Tier A duel pack reader for v5_tier_a. Does not alter production get_duel_pack.';
grant execute on function public.get_duel_pack_v5(uuid) to authenticated, anon, service_role;
-- STEP 4 + 6: validation + simulated function call with auth claim context
do $$
declare
  v_count integer;
  v_challenger uuid;
  v_bot_profile_id uuid;
  v_duel_id uuid := gen_random_uuid();
  v_question_ids text[];
  v_choices_order jsonb;
  v_payload jsonb;
  v_returned_ids text[];
  v_missing_count integer;
  v_bad_display_count integer;
begin
  select count(*) into v_count from public.dataset_questions where dataset_version = 'v5_tier_a';
  if v_count < 500 then
    raise exception 'validation_failed: expected approximately 584 rows for v5_tier_a, got %', v_count;
  end if;

  select player_id into v_challenger
  from public.player_profiles
  order by created_at
  limit 1;

  if v_challenger is null then
    raise exception 'validation_failed: no player_profiles row available to run get_duel_pack_v5 test';
  end if;

  select id into v_bot_profile_id
  from public.bot_profiles
  where active = true
  order by created_at
  limit 1;

  if v_bot_profile_id is null then
    raise exception 'validation_failed: no active bot_profiles row available to run get_duel_pack_v5 test';
  end if;

  select array_agg(question_id order by question_id) into v_question_ids
  from (
    select question_id from public.dataset_questions where dataset_version = 'v5_tier_a' and quality_tier = 'A' order by question_id limit 10
  ) s;

  if coalesce(array_length(v_question_ids, 1), 0) <> 10 then
    raise exception 'validation_failed: expected 10 test question ids, got %', coalesce(array_length(v_question_ids, 1), 0);
  end if;

  select jsonb_agg(jsonb_build_array('A','B','C','D')) into v_choices_order
  from generate_subscripts(v_question_ids, 1);

    id, challenger_id, opponent_id, is_bot_match, bot_profile_id, is_ranked, source,
    question_set, state, create_idempotency_key, challenge_expires_at,
    dataset_version, question_ids, choices_order, answer_map, content_hash, sealed_at
  ) values (
    v_duel_id, v_challenger, null, true, v_bot_profile_id, true, 'staging_v5_test',
    '[]'::jsonb, 'pending', 'staging_v5_test_' || replace(v_duel_id::text, '-', ''), now() + interval '24 hours',
    'v5_tier_a', v_question_ids, v_choices_order, '[]'::jsonb, encode(digest(v_duel_id::text, 'sha256'), 'hex'), now()
  );

  perform set_config('request.jwt.claim.sub', v_challenger::text, true);
  v_payload := public.get_duel_pack_v5(v_duel_id);

  if coalesce(v_payload->>'status','') <> 'ok' then
    raise exception 'validation_failed: get_duel_pack_v5 status not ok';
  end if;

  if jsonb_typeof(v_payload->'questions') <> 'array' then
    raise exception 'validation_failed: get_duel_pack_v5 questions payload is not an array';
  end if;

  if jsonb_array_length(v_payload->'questions') <> 10 then
    raise exception 'validation_failed: get_duel_pack_v5 expected 10 questions, got %', jsonb_array_length(v_payload->'questions');
  end if;

  select array_agg((elem->>'question_id')::text order by ord) into v_returned_ids
  from jsonb_array_elements(v_payload->'questions') with ordinality as q(elem, ord);

  if v_returned_ids is distinct from v_question_ids then
    raise exception 'validation_failed: get_duel_pack_v5 question ordering mismatch';
  end if;

  select count(*) into v_missing_count
  from unnest(v_returned_ids) as rid(question_id)
  left join public.dataset_questions dq
    on dq.question_id = rid.question_id and dq.dataset_version = 'v5_tier_a' and dq.quality_tier = 'A'
  where dq.question_id is null;

  if v_missing_count > 0 then
    raise exception 'validation_failed: get_duel_pack_v5 returned non Tier A / non v5 questions';
  end if;

  select count(*) into v_bad_display_count
  from jsonb_array_elements(v_payload->'questions') as q(elem)
  where jsonb_typeof(elem->'display_order') <> 'array' or jsonb_array_length(elem->'display_order') <> 4;

  if v_bad_display_count > 0 then
    raise exception 'validation_failed: malformed display_order in get_duel_pack_v5';
  end if;

  delete from public.duel_challenges where id = v_duel_id;
end
$$;
commit;
